jQuery(document).ready(function($){function confirmFormChange(){formmodified=1}
function initialiseCodeMirror($element,mode){if(!$element.length||typeof wp.codeEditor!=='object'){return}
if($element.data('codemirror-initialised')){return}
const editorSettings=wp.codeEditor.defaultSettings?_.clone(wp.codeEditor.defaultSettings):{};editorSettings.codemirror=_.extend({},editorSettings.codemirror,mode?{mode:mode}:{});const editor=wp.codeEditor.initialize($element,editorSettings);editor.codemirror.on('change',confirmFormChange);$element.data('codemirror-initialised',!0)}
$('.codemirror_html').each(function(){initialiseCodeMirror($(this),null)});$('.codemirror_js').each(function(){initialiseCodeMirror($(this),'javascript')});$('.codemirror_css').each(function(){initialiseCodeMirror($(this),'css')})})